section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/spatial-interaction-patterns.json",
  "title": "Spatial Interaction Patterns",
  "type": "object",
  "required": [
    "artefact_id",
    "feature_id",
    "primary_modality",
    "fallback_modality",
    "interaction_pattern",
    "a11y_path",
    "device_targets",
    "evidence",
    "owner",
    "status",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "feature_id": {
      "type": "string",
      "description": "feature_id",
      "minLength": 1
    },
    "primary_modality": {
      "type": "string",
      "description": "primary_modality",
      "minLength": 1
    },
    "fallback_modality": {
      "type": "string",
      "description": "fallback_modality",
      "minLength": 1
    },
    "interaction_pattern": {
      "type": "array",
      "description": "interaction_pattern (array)",
      "minItems": 1
    },
    "a11y_path": {
      "type": "string",
      "description": "a11y_path",
      "minLength": 1
    },
    "device_targets": {
      "type": "array",
      "description": "device_targets (array)",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
